const msg = $input.first().json.message || {};
const chatId = msg.chat?.id;
const text = (msg.text || '').trim();

if (!chatId || !text) {
  // Not a text message (photo, sticker, etc.) — handled by other workflows
  return [];
}

const lower = text.toLowerCase();

// These commands belong to other workflows — ignore them here
if (lower.startsWith('/help') || lower.startsWith('/start') ||
    lower.startsWith('/water') || lower.startsWith('/food') ||
    lower.startsWith('/weight')) {
  return [];
}

// /resume [job description] → generate resume
if (lower.startsWith('/resume')) {
  const jd = text.replace(/^\/resume\s*/i, '').trim();
  if (!jd) {
    return [{ json: { type: 'prompt_jd', chatId, text } }];
  }
  return [{ json: { type: 'resume', chatId, jobDescription: jd } }];
}

// Plain long text (> 200 chars) not starting with / → treat as job description
if (text.length > 200 && !text.startsWith('/')) {
  return [{ json: { type: 'resume', chatId, jobDescription: text } }];
}

// Everything else → ignore
return [];

const jobDescription = $('Parse Message').first().json.jobDescription;
const chatId = $('Parse Message').first().json.chatId;
const resumeText = $json.defaultResume;

const systemPrompt = `You are an elite resume writer and ATS optimization specialist.
Your job: produce a LaTeX resume that maximally matches the job description and passes ATS screening.

## OPTIMIZATION STEPS
1. Extract all required/preferred skills, tools, cloud services, and keywords from the JD
2. Mirror those EXACT keywords in the resume (ATS keyword matching)
3. Reorder experience bullets - most JD-relevant achievements come first
4. Every bullet must have a quantified metric (%, $, x faster, # requests, # users)
5. Use strong action verbs: Architected, Engineered, Spearheaded, Automated, Reduced, Scaled
6. Remove irrelevant content; add context that reinforces JD requirements

## LATEX RULES
- Use ONLY these packages: geometry, hyperref, enumitem, titlesec, parskip, fontenc, inputenc, array, booktabs
- DO NOT use: fontawesome, fontawesome5, moderncv, tikz
- Clean single-column layout (ATS-friendly)
- Font size: 10pt or 11pt, margins: 0.65in-0.75in
- Section headers: bold with horizontal rule
- Bullet points: tight spacing with enumitem
- Hyperlinked email
- Target: 1 page

## OUTPUT FORMAT
Return ONLY valid compilable LaTeX. Start with documentclass, end with end{document}. No markdown, no fences.`;

const userPrompt = `Optimize and rewrite this resume for the job description below.

=== JOB DESCRIPTION ===
${jobDescription}

=== CANDIDATE RESUME ===
${resumeText}

Return ONLY LaTeX code.`;

// Build the full Claude API body here to avoid JSON injection in HTTP node
const claudeBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  system: systemPrompt,
  messages: [
    { role: 'user', content: userPrompt }
  ]
};

return [{
  json: {
    chatId,
    jobDescription,
    claudeBody,
    startTime: Date.now()
  }
}];

const claudeResponse = $input.first().json;
const promptData = $('Build Claude Prompt').first().json;

let latexCode = '';
if (claudeResponse.content && Array.isArray(claudeResponse.content)) {
  for (const block of claudeResponse.content) {
    if (block.type === 'text' && block.text) {
      latexCode = block.text;
      break;
    }
  }
}

if (!latexCode) {
  throw new Error('Claude returned empty response: ' + JSON.stringify(claudeResponse).substring(0, 200));
}

// Strip markdown fences if present
latexCode = latexCode
  .replace(/^```(?:latex|tex|\s*)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

if (!latexCode.includes('\\documentclass')) {
  throw new Error('Invalid LaTeX from Claude: ' + latexCode.substring(0, 200));
}

if (!latexCode.includes('\\end{document}')) {
  latexCode += '\n\\end{document}';
}

const model = claudeResponse.model || 'claude-opus-4-6';
const inputTokens = claudeResponse.usage?.input_tokens || 0;
const outputTokens = claudeResponse.usage?.output_tokens || 0;
const elapsed = Math.round((Date.now() - (promptData.startTime || Date.now())) / 1000);

return [{
  json: {
    latexCode,
    chatId: promptData.chatId,
    model,
    inputTokens,
    outputTokens,
    elapsedSec: elapsed,
    lineCount: latexCode.split('\n').length
  }
}];
